        if constexpr (DO_AREA) {
          if (worst_arrival > node_data.required[phase] + epsilon)
            continue;
        }

        bool accept = false;
        if (compare_map<DO_AREA>(worst_arrival, best_arrival, area_local, best_area_flow, cut->size(), best_size)) {
            accept = true;
        } else {
            // Dynamic weighted probability with adaptive temperature
            double arrival_weight = 1.0 / (1.0 + sqrt(iteration)/30.0); // Smoother transition
            double area_weight = 1.0 - arrival_weight;
            double delta = arrival_weight * (worst_arrival - best_arrival) + 
                         area_weight * (area_local - best_area_flow);

            // Adaptive temperature scaling based on acceptance rate
            double adaptive_temp = temperature * (1.0 + (iteration - accept_count)/5000.0);
            double probability = exp(-delta / adaptive_temp);
            accept = (rand() / (double)RAND_MAX) < probability;

            iteration++;
            if (accept) accept_count++;
        }

        if (accept) {
            best_arrival = worst_arrival;
            best_area_flow = area_local;
            best_size = cut->size();
            best_cut = cut_index;
            best_area = gate.area;
            best_phase = gate_polarity;
            best_supergate = &gate;
        }
      }

